// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('text', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('text', async function() {
    await driver.get("http://localhost:4200/admin-user/add-user");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    assert(await driver.findElement(By.css(".ant-typography")).getText() == "ユーザ追加");
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(1) .ant-form-item-no-colon")).getText() == "部署");
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(2) .ant-form-item-no-colon")).getText() == "氏名/メール");
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(2)")).getText() == "氏名");
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(3)")).getText() == "会社");
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(4)")).getText() == "部署一覧");
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(5)")).getText() == "メール");
    assert(await driver.findElement(By.css(".ant-table-placeholder > .ant-table-cell")).getText() == "該当データがありません");
  });
});
